-- в”Ђв”Ђ Collective Health в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Collective Health is a technology-driven third party administrator (TPA) that helps self-insured US employers run medical, dental, vision and pharmacy benefits from a single platform. It combines plan administration, claims processing, cost management and member navigation with a consumer-facing app and care team. Founded in 2013 and based in San Francisco, it serves large and mid-market employers such as Uber, Zoom, Red Bull and Live Nation.$q$, short_description),
  pricing_model = COALESCE($q$Custom, quote-based enterprise pricing tied to employer group size, plan design and module selection, typically structured as a medical plan administration fee plus network access fees and optional add-on modules; there is no self-serve checkout or published price list$q$, pricing_model),
  starting_price = COALESCE($q$Not publicly disclosed - custom enterprise quote required$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Privately held; reported to have roughly 1,000-2,000 employees, though an exact current headcount is not fully disclosed publicly$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Collective Health Review 2026: Pricing, Features and FAQs$q$, seo_title),
  seo_meta_description = COALESCE($q$Collective Health is a TPA platform for self-insured employers combining benefits administration, claims and member navigation. See pricing, features and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Collective Health is a San Francisco-based health technology company, founded in 2013, that operates as an independent third party administrator (TPA) for self-insured US employers. Rather than acting as a traditional health insurance carrier, Collective Health sits on top of an employer's chosen medical network and stop-loss coverage, handling plan administration, claims adjudication, eligibility, billing reconciliation and member support through one connected software platform. The company describes its model as combining the cost-control flexibility of a carved-out benefits program with the simplicity of a single carved-in member experience, which is the core value proposition that differentiates it from legacy TPAs and fully-insured carriers. Employers that use Collective Health are typically mid-market to large organizations that have already moved to self-funded health plans, or are actively considering the switch, since self-insurance gives them more control over plan design and claims data in exchange for taking on more financial risk, which Collective Health's software and services are built to help manage. Reported clients include Red Bull, The Wonderful Company, Boot Barn, Live Nation, Driscoll's, Uber and Zoom, and the company states it serves more than 800,000 members across all 50 states and has processed roughly 25 billion dollars in medical claims since founding, with internally reported claims processing accuracy above 99.9 percent as of 2024 audits. On the member side, Collective Health provides a mobile app and web portal where employees can view digital ID cards, track claims and deductibles, message a dedicated Care Team for help resolving billing issues or finding in-network providers, and access curated third-party health and wellness point solutions through what the company calls the Partner Collective, an ecosystem of more than 140 vetted vendors spanning categories such as mental health, musculoskeletal care, fertility, and chronic condition management. On the employer side, HR and benefits teams get analytics dashboards for tracking utilization and cost trends, tools for COBRA and compliance administration, and a single point of coordination instead of managing separate contracts with a TPA, network, and multiple point-solution vendors individually. Pricing is not published; Collective Health sells through an enterprise sales process and quotes are based on group size, selected modules, and network arrangements, which means prospective customers cannot get exact costs without engaging sales. The company has raised substantial venture funding over its history and has been positioned as one of the more prominent independent players in the benefits administration and health navigation space, competing with both legacy TPAs offered by large insurance carriers and newer point-solution aggregators. Because Collective Health is a B2B enterprise platform sold to employers rather than a consumer product, individual employees typically cannot sign up directly; access comes through an employer's benefits program. The platform is US-only and is built around US employer-sponsored insurance structures, so it does not address international or multi-country benefits administration. For a directory or comparison context, Collective Health is most relevant to HR, benefits, and people-operations audiences researching TPA and benefits-administration options for self-insured plans, rather than to consumers shopping for individual health coverage.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '72113a07-d836-42b2-bc28-ca8584b4dde2';

