-- в”Ђв”Ђ Colobot в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Colobot: Gold Edition is a free, open-source real-time strategy game in which players write programs in CBOT, a language modeled closely on C++ and Java, to control robots exploring and defending alien planets. The original Colobot was released commercially by Swiss studio Epsitec in 2001; its source code was released under an open license in 2012 and the game is now maintained by the volunteer TerranovaTeam and community. It is sometimes used in schools as a teaching aid for introducing programming fundamentals.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source under the GNU General Public License; there are no paid tiers, subscriptions or in-app purchases$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE($q$Not applicable - Colobot: Gold Edition is a volunteer-run open-source community project (TerranovaTeam), not a company$q$, company_size),
  headquarters = COALESCE($q$Not applicable - distributed open-source community project; the original 2001 game was developed by Epsitec SA in Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Polish$q$]::text[],
  seo_title = COALESCE($q$Colobot: Gold Edition - Free Open-Source Coding Game$q$, seo_title),
  seo_meta_description = COALESCE($q$Colobot: Gold Edition is a free open-source strategy game that teaches programming through CBOT, a C-like scripting language. Features, history and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Colobot, formally known in its current form as Colobot: Gold Edition, is a free and open-source educational real-time strategy game centered on teaching programming concepts through gameplay. The original Colobot was developed and published commercially in 2001 by the Swiss studio Epsitec SA, releasing in English, French, German and Polish versions for Windows. In the game, the player takes the role of an astronaut leading a space expedition tasked with finding a new habitable planet after Earth becomes uninhabitable; rather than controlling robots and vehicles directly with a mouse and keyboard in the traditional real-time-strategy sense, the player writes programs in CBOT, a scripting language deliberately designed to closely resemble C++ and Java syntax, to direct robots to prospect for resources, transport materials, construct buildings, research technology and defend against hostile alien life. This design choice differentiates Colobot from block-based educational coding tools such as Scratch: rather than abstracting programming into drag-and-drop blocks, Colobot has players write real, C-like procedural code with variables, loops, conditionals, functions and object-oriented concepts, with the game's missions structured to introduce these concepts progressively as campaign difficulty increases. In March 2012, after a sustained community campaign led by Polish fans (organized as the Polish Portal of Colobot), Epsitec agreed to release the original game's source code under an open-source license. A group of community developers and contributors, organized as TerranovaTeam, subsequently built Colobot: Gold Edition on top of that codebase, restoring, modernizing and expanding the original game for current operating systems. Colobot: Gold Edition is distributed as free and open-source software under the GNU General Public License, with active development hosted publicly on GitHub, and it runs on Windows, Linux and macOS. Compared with the original 38-mission commercial release, Gold Edition adds more than 40 additional missions integrated into extended campaign story arcs across familiar planetary settings, plus new game modes: Missions+ offers additional structured challenges, and CodeBattles (introduced around version 0.1.6) lets players write competing bot programs that are then set loose to battle autonomously without further player intervention, testing the robustness of their code under competitive conditions. The community also maintains a free-play sandbox mode for open-ended base building, and supports user-created mods, custom levels and additional assets shared through sites like ModDB and the official Colobot community site. Notably, Colobot has been recognized outside its own community as an educational tool: it has reportedly been recommended by Poland's Ministry of National Education as a teaching aid for introducing algorithms and object-oriented programming concepts in schools, and it appears in the Free Software Foundation's Free Software Directory as free educational software. Because CBOT's syntax closely mirrors mainstream languages like C++ and Java, reviewers and educators generally position Colobot as best suited to learners who already have some basic familiarity with procedural programming, functioning more as a way to practice and reinforce real coding syntax through an engaging strategy-game wrapper than as a first introduction to programming for absolute beginners. As an actively but slowly developed volunteer project (recent builds are still labeled alpha, for example alpha-0.1.12 and later), Colobot lacks the polish, marketing and extensive third-party tutorial ecosystem of commercial coding-education platforms, but it remains a notable example of a fully free, community-maintained game built specifically around teaching real programming syntax.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'be9bb1a6-1bfa-468a-b4ce-ad7f245bb353';

