-- в”Ђв”Ђ Comeet в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Comeet is a collaborative applicant tracking system (ATS) originally built in Tel Aviv, Israel, in 2013 to help growing companies source, screen and hire talent. In 2023 Comeet merged with video-interviewing platform Spark Hire, and as of January 2025 the combined product is marketed as Spark Hire Recruit, formerly Comeet. It remains focused on structured, collaborative hiring workflows for small and mid-sized companies.$q$, short_description),
  pricing_model = COALESCE($q$Subscription pricing, generally quoted per user or per active job requisition per month; current tiers are provided via vendor quote rather than a fully public self-serve price list$q$, pricing_model),
  starting_price = COALESCE($q$Not officially published; third-party review sites have cited plans starting around 50 USD per user per month, though this should be confirmed directly with sales$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Estimated 51-200 employees historically as an independent company; now operates as part of Spark Hire following their 2023 merger$q$, company_size),
  headquarters = COALESCE($q$Originally headquartered in Tel Aviv, Israel with a US office in Palo Alto, California; now operates under Spark Hire, headquartered in Highland Park, Illinois, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Comeet (Spark Hire Recruit) Review: ATS Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Comeet, now Spark Hire Recruit, is a collaborative applicant tracking system. See features, pricing, pros, cons and FAQs for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Comeet is a collaborative applicant tracking system (ATS) founded in 2013 by Omer Gottlieb, Omer Tadjer, Shahar Ben David and Tomer Dikerman, initially built in Tel Aviv, Israel with a subsequent US office established in Palo Alto, California through the UpWest Labs accelerator program. The product was designed around the idea of collaborative recruiting: rather than treating hiring as a task owned solely by a recruiter, Comeet built workflows that pull hiring managers, interviewers and executives directly into a shared candidate pipeline, with tools for structured interview scorecards, hiring plan visibility and multi-channel sourcing across job boards, social media and a company's own careers site. Over the following decade Comeet built out AI-assisted features, including an assistant that helps generate interview scorecards and suggested interview questions based on recruiting best practices, and it integrated with adjacent HR tools such as ADP (where it has historically been listed on the ADP Marketplace) and applicant-sourcing platforms like Gem. In 2023, Comeet merged with Spark Hire, a long-established video interviewing and hiring-assessment platform founded in 2010 and headquartered in Highland Park, Illinois; for a period the two operated under a combined go-to-market while retaining separate product identities, but as of January 2025 the ATS product has been formally rebranded as Spark Hire Recruit, described publicly as Spark Hire Recruit, formerly Comeet, reflecting a full integration of the Comeet ATS into Spark Hire's broader hiring platform alongside its video interviewing and assessment tools. This means that prospective buyers researching Comeet today are effectively evaluating Spark Hire Recruit, and the standalone Comeet brand, while still visible in legacy marketing materials, integration directories and historical reviews, is being phased out in favor of the combined Spark Hire identity. The product itself continues to focus on small and mid-sized companies, historically estimated at around 51 to 200 employees as an independent business, that want a full-cycle recruiting workflow without the complexity or cost of larger enterprise-grade ATS platforms such as Greenhouse or Lever. Comeet's pricing has never been fully published; third-party software review and comparison sites have cited starting costs in the range of roughly 50 US dollars per user per month, but Comeet (and now Spark Hire Recruit) sells primarily through a sales-quote process, so exact current pricing, plan tiers and any minimum contract terms require contacting the vendor directly. User feedback historically cited in third-party reviews has generally been positive around ease of use, collaborative hiring-manager involvement and search/filtering capability within candidate databases, positioning Comeet as a strong fit for growing companies that want a straightforward, affordable ATS with genuine collaboration features rather than the most feature-dense enterprise platform on the market. For a directory profile in 2026, the most important fact to surface is the corporate status: Comeet is not an actively marketed standalone brand anymore, having been absorbed into Spark Hire Recruit after the 2023 merger and January 2025 rebrand, so users searching for Comeet today will generally be directed to Spark Hire's product and sales pages rather than an independent Comeet website experience.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ecc248c8-d683-44ea-8e90-40d9194740c1';

