-- в”Ђв”Ђ Comfy в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Comfy is an enterprise workplace experience platform that lets employees book desks and meeting rooms, navigate offices, find colleagues, and control comfort settings like temperature and lighting from a mobile app. Originally launched in 2013 by Oakland startup Building Robotics, it was acquired by Siemens in 2018 and now operates as part of Siemens Smart Infrastructure, often paired with Siemens-owned Enlighted IoT sensors for real-time occupancy data. This Comfy is unrelated to the open-source ComfyUI image-generation tool.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise B2B licensing, quoted per building, floor or user seat and typically sold alongside broader Siemens Smart Infrastructure building-technology contracts; pricing is not publicly listed$q$, pricing_model),
  starting_price = COALESCE($q$Not publicly disclosed - custom enterprise quote required through Siemens Smart Infrastructure$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Comfy originated as a small startup team (Building Robotics); it now operates within Siemens Smart Infrastructure, part of Siemens AG, which employs roughly 300,000 people worldwide$q$, company_size),
  headquarters = COALESCE($q$Originally based in Oakland, California, United States (as Building Robotics); now part of Siemens Smart Infrastructure, headquartered in Zug, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Comfy Workplace App Review: Siemens Smart Infrastructure$q$, seo_title),
  seo_meta_description = COALESCE($q$Comfy is Siemens' workplace experience app for desk booking, room reservations and occupancy analytics. Learn features, pricing model and FAQs for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Comfy is a workplace experience and smart-building application that helps organizations make their offices more responsive to how employees actually use them. It originated as the flagship product of Building Robotics Inc., a startup founded in 2013 in Oakland, California by two UC Berkeley engineering PhD students, Andrew Krioukov and Stephen Dawson-Haggerty, who built the app around combining building sensor data with individual employee preferences. In June 2018, Siemens acquired Building Robotics to strengthen its digital building-technology portfolio, and the Comfy product has since been integrated into Siemens Smart Infrastructure, the Siemens division focused on intelligent infrastructure for buildings, cities, industry and grids, headquartered in Zug, Switzerland. It is important to disambiguate this Comfy from the unrelated, similarly named open-source tool ComfyUI, a node-based interface for Stable Diffusion image generation; the two share no corporate or technical relationship, and this entry refers exclusively to the enterprise workplace-experience Comfy owned by Siemens. Functionally, Comfy lets employees use a mobile or web app to reserve individual desks and meeting rooms (particularly useful for organizations running hybrid or hot-desking office models), navigate buildings and campuses via interactive maps, locate coworkers who are in the office on a given day, and personalize their immediate environment by adjusting temperature and lighting levels in supported spaces. On the backend, Comfy integrates with Siemens-owned Enlighted, a separate IoT sensor company Siemens also acquired, to layer in real-time occupancy sensing across desks, rooms and whole floors; this sensor data feeds both the employee-facing app (so people can see live availability before walking to a room) and Comfy Insights, an analytics dashboard aimed at facilities and real estate teams that shows how office space is actually being used over time, supporting decisions about space consolidation, layout changes and lease planning. Following the acquisition, Siemens made a public commitment to deploy Comfy broadly across its own real estate, targeting roughly 600 Siemens office locations and more than 100,000 Siemens employees across 30 countries, both as an internal efficiency initiative and as a visible reference deployment for prospective external customers. Siemens has continued to expand Comfy's feature set since the acquisition, including adding hybrid-work collaboration tools aimed at helping distributed teams coordinate in-office days. As part of Siemens Smart Infrastructure, Comfy is generally sold as an enterprise contract bundled with or adjacent to other Siemens building-technology offerings rather than as a self-serve SaaS product with published pricing; prospective customers work with a Siemens sales team, and costs scale with the number of buildings, floors, sensors and users covered. Comfy is most relevant to corporate real estate, facilities management and workplace experience teams at large, often multinational, enterprises that are managing hybrid work policies and want data-driven insight into how much office space they actually need, rather than to small businesses or individual consumers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '779920fd-e21a-4301-86be-66403583d8ad';

