-- в”Ђв”Ђ CommandBar в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$CommandBar (later rebranded Command AI) was a New York-based startup, founded in 2020, that built an in-app command palette, product-guidance and AI copilot platform for SaaS products, offering Spotlight search, in-app Nudges, and an AI-powered Copilot assistant. Amplitude acquired the company, with the deal announced in October 2024, and relaunched the product in February 2025 as Amplitude Guides and Surveys, now sold as part of the Amplitude product analytics platform rather than as a standalone tool.$q$, short_description),
  pricing_model = COALESCE($q$As an independent product, CommandBar/Command AI used flat-rate monthly or annual subscription tiers scaled by monthly active users (MAU), with AI Copilot features bundled into the subscription rather than billed separately; the product is now sold as part of Amplitude's platform and pricing, following the Amplitude acquisition$q$, pricing_model),
  starting_price = COALESCE($q$Historically around 249 USD per month for entry tiers, with Growth-tier plans starting near 899 USD per month for 5,000 MAU and enterprise deals often exceeding 30,000 USD annually; current pricing is set through Amplitude as Guides and Surveys$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small startup team prior to acquisition (Y Combinator-backed); now operates within Amplitude, which employs roughly 1,000 people$q$, company_size),
  headquarters = COALESCE($q$Originally headquartered in New York, New York, United States; now operates as part of Amplitude, headquartered in San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CommandBar Review 2026: Now Amplitude Guides and Surveys$q$, seo_title),
  seo_meta_description = COALESCE($q$CommandBar built in-app command palettes and an AI copilot for SaaS products. Now part of Amplitude as Guides and Surveys. Features, pricing and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CommandBar was a Y Combinator-backed startup founded in 2020 by James Evans, Richard Freling and Vinay Ayyala, headquartered in New York City, that set out to bring a command-palette style, keyboard-shortcut-driven interface, similar to the command-k or cmd+k pattern found in tools like Linear and Superhuman, to any SaaS product as an embeddable, no-code layer. The company's initial pitch was described internally as cmd+k as a service: rather than every product team building its own search-and-navigation command palette from scratch, CommandBar offered a drop-in widget that indexed a product's features, pages and help content so end users could jump to any action or destination instantly via keyboard shortcut or search. Over time CommandBar expanded well beyond a pure command palette into a broader in-app user-assistance and product-led-growth platform built around three core products: Spotlight, a universal in-app search and navigation tool; Nudges, a system for triggering contextual in-product messages, tooltips and walkthroughs based on user behavior; and Copilot, an AI-powered chat assistant that could answer user questions, walk users through how a feature works via co-browsing, and in more advanced configurations take actions on a user's behalf inside the host application. This combination positioned CommandBar as a user-onboarding, self-service-support and product-adoption tool for SaaS companies trying to reduce support ticket volume and improve feature discovery without constant manual intervention from customer success teams. As an independent company, CommandBar's pricing followed a flat-rate SaaS subscription model tied to monthly active users (MAU) rather than charging separately for the AI Copilot features, with entry-level plans reported to start around 249 US dollars per month, Growth-tier plans starting near 899 US dollars per month for up to 5,000 MAU, and enterprise customers who added premium support or scaled well beyond base tiers commonly reaching roughly 30,000 US dollars or more annually. In October 2024, product analytics company Amplitude announced its acquisition of CommandBar (by then also operating under the brand Command AI), and in February 2025 Amplitude publicly launched the combined offering under the name Amplitude Guides and Surveys, explicitly built by combining Command AI's in-app guidance and assistant technology with Amplitude's existing behavioral analytics data. The rebranded product is now positioned as an in-product engagement module inside the broader Amplitude platform, letting teams launch guides, tooltips, announcements and surveys that are triggered by real user behavior tracked in Amplitude, and pair every guide or survey with session replay and A/B testing data rather than treating engagement as a disconnected tool. Because of this acquisition and rebrand, CommandBar as a standalone, independently branded and independently priced product effectively no longer exists in the market as of 2026; researchers, buyers and directory users looking into CommandBar today are, in practice, evaluating Amplitude Guides and Surveys, and should expect CommandBar's original website, documentation and self-serve signup flows to redirect toward Amplitude's product pages and sales process rather than an independent CommandBar storefront.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '862d01e4-b70f-42d4-a767-087af055aa04';

